sql:
SELECT dealer_name, location, phone_number, email
FROM dealers
WHERE dealer_id = 1;

SELECT COUNT(*) AS NumberOfVehicles
FROM vehicles
WHERE mileage > 10000;

SELECT DISTINCT vehicle_id
FROM sales
WHERE strftime('%Y', sale_date) = '2020';

