- "entered the electrified galaxy" implies the vehicles are electric vehicles (is_ev = 1);
- "fleet controlled by a chosen manufacturer" indicates the make_id;
- "shine with" refers to the features (feature_name);
- "specific constellation" refers to the type_id;
- "star trader" metaphorically represents the dealer_id.

sql:
SELECT name 
FROM vehicles 
WHERE vehicle_id NOT IN (SELECT vehicle_id FROM sales);

SELECT vehicles.name, vehicle_types.type_name 
FROM vehicles 
JOIN vehicle_types ON vehicles.type_id = vehicle_types.type_id;

SELECT vehicle_id, feature_name
FROM vehicle_features
WHERE feature_name = 'sunroof';

SELECT v.name, s.sale_price
FROM vehicles v
JOIN sales s ON v.vehicle_id = s.vehicle_id;
